import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
// 导入我们的领域对象 store
import { createGameStore } from '../../../domain/gameStore.js';

// 使用我们的领域对象 store
const gameStore = createGameStore();

// 从 gameStore 派生出旧接口需要的状态
const { subscribe: subscribeGame, setGrid, guess, undo, redo, toJSON } = gameStore;

// 派生出旧的 grid store 接口（只读）
const grid = {
  subscribe(callback) {
    return subscribeGame(state => {
      callback(state.givens);
    });
  },

  generate(difficulty) {
    const newGrid = generateSudoku(difficulty);
    setGrid(newGrid);
  },

  decodeSencode(sencode) {
    const newGrid = decodeSencode(sencode);
    setGrid(newGrid);
  },

  get(gridStore, x, y) {
    return gridStore[y][x];
  },

  getSencode(gridStore) {
    return encodeSudoku(gridStore);
  },
};

// 派生出旧的 userGrid store 接口
const userGrid = {
  subscribe(callback) {
    return subscribeGame(state => {
      callback(state.grid);
    });
  },

  set(pos, value) {
    if (pos.x !== null && pos.y !== null) {
      guess({ row: pos.y, col: pos.x, value });
    }
  },

  applyHint(pos) {
    hints.useHint();
    // 获取当前 grid 并求解
    subscribeGame(state => {
      const solvedSudoku = solveSudoku(state.grid);
      if (pos.x !== null && pos.y !== null) {
        guess({ row: pos.y, col: pos.x, value: solvedSudoku[pos.y][pos.x] });
      }
    })();
  },
};

// 派生出旧的 invalidCells store
const invalidCells = derived(
  { subscribe: subscribeGame },
  ($game) => $game.invalidCells,
  []
);

// 新增：导出 canUndo 和 canRedo 供 UI 使用
export const canUndo = derived(
  { subscribe: subscribeGame },
  ($game) => $game.canUndo,
  false
);

export const canRedo = derived(
  { subscribe: subscribeGame },
  ($game) => $game.canRedo,
  false
);

// 新增：导出 won 状态
export const gameWon = derived(
  { subscribe: subscribeGame },
  ($game) => $game.won,
  false
);

// 新增：导出 undo 和 redo 函数供 UI 使用
export function undoMove() {
  undo();
}

export function redoMove() {
  redo();
}

// 保持原有导出接口不变
export { grid, userGrid, invalidCells };
